import Image from "next/image";
import Link from "next/link";
import { Asterisk } from "lucide-react";
import { getProjectBySlug } from "@/data/projects";

/**
 * Page de détail d'un projet, affichant une image principale et un titre stylisé.
 * @param param0 - Les paramètres de la route, incluant le slug du projet.
 * @returns Un composant React représentant la page de détail du projet.
 */
export default async function ProjectDetailPage({ params }: { params: Promise<{ slug: string }> }) {
  const { slug } = await params; // Récupération du slug à partir des paramètres de la route (slug = nom du projet dans l'URL)
  const project = getProjectBySlug(slug);

  if (!project) {
    return (
      <main className="min-h-screen bg-[#121212] flex items-center justify-center">
        <p className="text-white">Projet non trouvé</p>
      </main>
    );
  }

  return (
    <main className="min-h-screen bg-[#121212]">
      {/* =========================================
          1. SECTION VISUELLE PRINCIPALE (Hero Image / Showcase)
          ========================================= */}
      <section className="relative w-full">
        {/* Conteneur image - sombre, grand format */}
        <div className="relative w-full h-[85vh] md:h-[75vh] lg:h-[80vh] overflow-hidden">
          {/* Image du projet - centered, contain pour préserver le ratio */}
          <Image
            src={project.image}
            alt={`${project.title} - Project showcase`}
            fill
            className="object-contain"
            priority
          />

          {/* Navigation - Positionnée en absolu en bas de l'image */}
          <nav className="absolute bottom-6 left-0 right-0 flex justify-between items-center px-8 md:px-16">
            {/* BACK - À gauche */}
            <Link href="/projects" className="text-xs md:text-sm tracking-[0.25em] uppercase text-white/70 hover:text-white transition-colors">
              Back
            </Link>

            {/* HOME - Au centre */}
            <Link href="/" className="text-xs md:text-sm tracking-[0.25em] uppercase text-white/70 hover:text-white transition-colors">
              Home
            </Link>

            {/* NEXT - À droite */}
            <span className="text-xs md:text-sm tracking-[0.25em] uppercase text-white/30 cursor-not-allowed">
              Next
            </span>
          </nav>
        </div>
      </section>

      {/* =========================================
          2. BANDEAU DE TITRE DU PROJET
          ========================================= */}
      <section className="bg-[#f4f5f0] px-6 py-12 md:py-16">
        {/* Titre avec astérisques - Flexbox centré */}
        <div className="flex items-center justify-center gap-4 md:gap-8 lg:gap-12">
          {/* Astérisque gauche */}
          <Asterisk className="w-4 h-4 md:w-5 md:h-5 text-gray-900/60 rotate-45" />

          {/* Titre principal - Police Script */}
          <h1 className="font-script text-4xl md:text-5xl lg:text-7xl text-gray-900 whitespace-nowrap">
            {project.title}
          </h1>

          {/* Astérisque droit */}
          <Asterisk className="w-4 h-4 md:w-5 md:h-5 text-gray-900/60 rotate-45" />
        </div>
      </section>
    </main>
  );
}